module RefModule (
    input clk,
    input reset,
    input d,
    input enable,
    output q );reg q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q_reg <= 1'b0;
        else if (enable)
            q_reg <= d;
    end

    assign q = q_reg;

endmodule
